"use strict";const errcode=require("../index"),expect=require("expect.js");describe("errcode",()=>{describe("string as first argument",()=>{it("should throw an error",()=>{expect(()=>{errcode("my message")}).to.throwError(e=>{expect(e).to.be.a(TypeError)})})}),describe("error as first argument",()=>{it("should accept an error and do nothing",()=>{const e=new Error("my message"),r=errcode(e);expect(r).to.be(e),expect(r.hasOwnProperty(r.code)).to.be(!1)}),it("should accept an error and add a code",()=>{const e=new Error("my message"),r=errcode(e,"ESOME");expect(r).to.be(e),expect(r.code).to.be("ESOME")}),it("should accept an error object and add code & properties",()=>{const e=new Error("my message"),r=errcode(e,"ESOME",{foo:"bar",bar:"foo"});expect(r).to.be.an(Error),expect(r.code).to.be("ESOME"),expect(r.foo).to.be("bar"),expect(r.bar).to.be("foo")}),it("should create an error object without code but with properties",()=>{const e=new Error("my message"),r=errcode(e,{foo:"bar",bar:"foo"});expect(r).to.be.an(Error),expect(r.code).to.be(void 0),expect(r.foo).to.be("bar"),expect(r.bar).to.be("foo")}),it("should set a non-writable field",()=>{const e=new Error("my message");Object.defineProperty(e,"code",{value:"derp",writable:!1});const r=errcode(e,"ERR_WAT");expect(r).to.be.an(Error),expect(r.stack).to.equal(e.stack),expect(r.code).to.be("ERR_WAT")}),it("should add a code to frozen object",()=>{const e=new Error("my message"),r=errcode(Object.freeze(e),"ERR_WAT");expect(r).to.be.an(Error),expect(r.stack).to.equal(e.stack),expect(r.code).to.be("ERR_WAT")}),it("should to set a field that throws at assignment time",()=>{const e=new Error("my message");Object.defineProperty(e,"code",{enumerable:!0,set(){throw new Error("Nope!")},get:()=>"derp"});const r=errcode(e,"ERR_WAT");expect(r).to.be.an(Error),expect(r.stack).to.equal(e.stack),expect(r.code).to.be("ERR_WAT")}),it("should retain error type",()=>{const e=new TypeError("my message");Object.defineProperty(e,"code",{value:"derp",writable:!1});const r=errcode(e,"ERR_WAT");expect(r).to.be.a(TypeError),expect(r.stack).to.equal(e.stack),expect(r.code).to.be("ERR_WAT")}),it("should add a code to a class that extends Error",()=>{class e extends Error{set code(e){throw new Error("Nope!")}}const r=new e("my message");Object.defineProperty(r,"code",{value:"derp",writable:!1,configurable:!1});const o=errcode(r,"ERR_WAT");expect(o).to.be.a(e),expect(o.stack).to.equal(r.stack),expect(o.code).to.be("ERR_WAT"),expect(()=>{new e("my message").code="derp"}).to.throwError()}),it("should support errors that are not Errors",()=>{const e=errcode({message:"Oh noes!"},"ERR_WAT");expect(e.message).to.be("Oh noes!"),expect(e.code).to.be("ERR_WAT")})}),describe("falsy first arguments",()=>{it("should not allow passing null as the first argument",()=>{expect(()=>{errcode(null)}).to.throwError(e=>{expect(e).to.be.a(TypeError)})}),it("should not allow passing undefined as the first argument",()=>{expect(()=>{errcode(void 0)}).to.throwError(e=>{expect(e).to.be.a(TypeError)})})})});